import{c as t,Q as r,j as e,m as o}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"第3章 あなたの 入行 ロードマップ","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part1-cognition/chapter3.md","filePath":"ja/part1-cognition/chapter3.md","lastUpdated":1779671667000}'),n={name:"ja/part1-cognition/chapter3.md"};function p(i,a,l,s,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="第3章-あなたの-入行-ロードマップ" tabindex="-1">第3章 あなたの 入行 ロードマップ <a class="header-anchor" href="#第3章-あなたの-入行-ロードマップ" aria-label="Permalink to &quot;第3章 あなたの 入行 ロードマップ&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>前2章では「能不能入行」と「要不要现在入行」の問題を解決しました。この章は認知篇の締めくくりとして、あなたに<strong>そのまま実行できるロードマップ</strong>を示します。</p><p>读完这章你会知道：</p><ul><li>あなたはどんなタイプの 入行 者か（後端/前端/ゼロベース/学生）、そしてあなただけの戦略</li><li>8週間 入行 スプリントプラン、毎週何をすべきか精确</li><li>6ヶ月深掘り進化プラン、「能动く」から「站得住」へ</li><li>学習リソースの選び方，哪些值得花钱，哪些免费够用</li></ul><p>看完这章，你应该就可以关掉书，打开电脑，开始执行了。</p><hr><h2 id="_3-1-四タイプの入門者像とそれぞれの戦略" tabindex="-1">3.1 四タイプの入門者像とそれぞれの戦略 <a class="header-anchor" href="#_3-1-四タイプの入門者像とそれぞれの戦略" aria-label="Permalink to &quot;3.1 四タイプの入門者像とそれぞれの戦略&quot;">​</a></h2><p>ロードマップを描く前に、首先问你一个问题：<strong>你是谁？</strong></p><p>AIへの 入行 に标准答案はない。出発点が異なれば、最適なパス也不同。</p><p>入門者を4つのタイプに分け、各タイプ都有自己的优势和坑。对号入座，找准属于你的策略。</p><hr><h3 id="タイプ1-後端からai開発への轉身" tabindex="-1">タイプ1：後端からAI開発への轉身 <a class="header-anchor" href="#タイプ1-後端からai開発への轉身" aria-label="Permalink to &quot;タイプ1：後端からAI開発への轉身&quot;">​</a></h3><p><strong>这样的人有哪些特徵</strong></p><p>1〜5年の後端開発経験があり、Java、Go、Python都可能、APIを書いたりサービスを構築したりデータベースと向き合ってきた，對你来说写代码不是问题，问题是「AI那边的代码怎么写」。</p><p><strong>你的优势</strong></p><p>最大の优势は<strong>エンジニアリング能力</strong>。很多人以为转AI要放弃工程能力，其实恰恰相反——2026年最も不足している人材は、AIモデルを安定して本番で動かせる人。</p><p>你懂高并发、服务治理、API设计、部署运维。这些东西、纯AI背景的人反而是短板。你的工程经验是你转型的护城河，不是负担。</p><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter3.html">中文版阅读</a></p></blockquote>',20)])])}const u=t(n,[["render",p]]);export{_ as __pageData,u as default};
